window.bookSummaryJSON = "<p>Aristotle is by far one of the most renown philosophers of all time. His philosophy has stood the test of time and his works have been analyzed and read around the world. This Aristotle collection contains four of Aristotle's most remarkable works: <i>Nicomachean Ethics</i>, <i>Politics</i>, <i>Rhetoric</i>, and <i>Poetics</i>.</p>"; 
